module InoutE2E(
  inout wire c,
  input logic clk,
  output logic q_comb,
  output logic q_ff,
  output logic c_drv
);
  logic c_next;

  assign c = c_drv;
  always_comb c_next = ~c;
  always_comb q_comb = c;

  always_ff @(posedge clk) begin
    q_ff <= c;
    c_drv <= c_next;
  end
endmodule
#include "InoutE2E.h"

#include <cstdint>
#include <iostream>

int main() {
  InoutE2E dut;
  const uint8_t pattern[] = {0, 1, 1, 0, 1, 0, 0, 1};
  bool allPass = true;

  dut.view.clk = 0;
  dut.view.c = 0;
  dut.view.q_comb = 0;
  dut.view.q_ff = 0;
  dut.eval();

  for (int cycle = 0; cycle < 8; ++cycle) {
    const uint8_t drive = pattern[cycle];
    dut.view.c = drive;

    dut.view.clk = 0;
    dut.eval();
    const int combRead = static_cast<int>(dut.view.q_comb);

    dut.view.clk = 1;
    dut.eval();
    const int ffRead = static_cast<int>(dut.view.q_ff);
    const bool pass = (combRead == static_cast<int>(drive)) &&
                      (ffRead == static_cast<int>(drive));
    allPass &= pass;

    std::cout << "cycle=" << cycle
              << " drive=" << static_cast<int>(drive)
              << " c_raw=" << static_cast<int>(dut.view.c)
              << " q_comb=" << combRead
              << " q_ff=" << ffRead
              << " check=" << (pass ? "PASS" : "FAIL") << "\n";
  }

  std::cout << (allPass ? "E2E_CHECK=PASS" : "E2E_CHECK=FAIL") << "\n";
  return allPass ? 0 : 1;
}
